// ── Markdown-to-ADF converter ──
function mdToAdf(md) {
  const lines = md.split('\n');
  const nodes = [];
  let i = 0;

  // Convert inline markdown to ADF text nodes with marks
  function inlineToAdf(text) {
    const parts = [];
    const regex = /(\*\*(.+?)\*\*|\*(.+?)\*|`([^`]+)`|\[([^\]]+)\]\(([^)]+)\))/g;
    let last = 0;
    let m;
    while ((m = regex.exec(text)) !== null) {
      if (m.index > last) parts.push({ type: 'text', text: text.slice(last, m.index) });
      if (m[2]) parts.push({ type: 'text', text: m[2], marks: [{ type: 'strong' }] });
      else if (m[3]) parts.push({ type: 'text', text: m[3], marks: [{ type: 'em' }] });
      else if (m[4]) parts.push({ type: 'text', text: m[4], marks: [{ type: 'code' }] });
      else if (m[5] && m[6]) parts.push({ type: 'text', text: m[5], marks: [{ type: 'link', attrs: { href: m[6] } }] });
      last = m.index + m[0].length;
    }
    if (last < text.length) parts.push({ type: 'text', text: text.slice(last) });
    if (parts.length === 0 && text) parts.push({ type: 'text', text });
    return parts;
  }

  while (i < lines.length) {
    const line = lines[i];

    // Code blocks
    if (line.startsWith('```')) {
      const lang = line.slice(3).trim() || null;
      const codeLines = [];
      i++;
      while (i < lines.length && !lines[i].startsWith('```')) { codeLines.push(lines[i]); i++; }
      i++; // skip closing ```
      const codeBlock = { type: 'codeBlock', content: [{ type: 'text', text: codeLines.join('\n') }] };
      if (lang) codeBlock.attrs = { language: lang };
      nodes.push(codeBlock);
      continue;
    }

    // Headings
    const headingMatch = line.match(/^(#{1,6}) (.+)$/);
    if (headingMatch) {
      nodes.push({ type: 'heading', attrs: { level: headingMatch[1].length }, content: inlineToAdf(headingMatch[2]) });
      i++; continue;
    }

    // Horizontal rule
    if (line.match(/^---+$/)) { nodes.push({ type: 'rule' }); i++; continue; }

    // Blockquote
    if (line.startsWith('> ')) {
      const quoteLines = [];
      while (i < lines.length && lines[i].startsWith('> ')) { quoteLines.push(lines[i].slice(2)); i++; }
      nodes.push({ type: 'blockquote', content: [{ type: 'paragraph', content: inlineToAdf(quoteLines.join(' ')) }] });
      continue;
    }

    // Bullet list
    if (line.match(/^[-*] /)) {
      const items = [];
      while (i < lines.length && lines[i].match(/^[-*] /)) {
        items.push({ type: 'listItem', content: [{ type: 'paragraph', content: inlineToAdf(lines[i].replace(/^[-*] /, '')) }] });
        i++;
      }
      nodes.push({ type: 'bulletList', content: items });
      continue;
    }

    // Numbered list
    if (line.match(/^\d+[.)]/)) {
      const items = [];
      while (i < lines.length && lines[i].match(/^\d+[.)]/)) {
        items.push({ type: 'listItem', content: [{ type: 'paragraph', content: inlineToAdf(lines[i].replace(/^\d+[.)] ?/, '')) }] });
        i++;
      }
      nodes.push({ type: 'orderedList', content: items });
      continue;
    }

    // Table
    if (line.match(/^\|.+\|$/) && i + 1 < lines.length && lines[i+1].match(/^\|[-| :]+\|$/)) {
      const headerCells = line.split('|').filter(c => c.trim()).map(c => ({
        type: 'tableHeader', content: [{ type: 'paragraph', content: inlineToAdf(c.trim()) }]
      }));
      const tableRows = [{ type: 'tableRow', content: headerCells }];
      i += 2; // skip header + separator
      while (i < lines.length && lines[i].match(/^\|.+\|$/)) {
        const cells = lines[i].split('|').filter(c => c.trim()).map(c => ({
          type: 'tableCell', content: [{ type: 'paragraph', content: inlineToAdf(c.trim()) }]
        }));
        tableRows.push({ type: 'tableRow', content: cells });
        i++;
      }
      nodes.push({ type: 'table', attrs: { isNumberColumnEnabled: false, layout: 'default' }, content: tableRows });
      continue;
    }

    // Empty line
    if (!line.trim()) { i++; continue; }

    // Paragraph (default)
    nodes.push({ type: 'paragraph', content: inlineToAdf(line) });
    i++;
  }

  return { type: 'doc', version: 1, content: nodes.length > 0 ? nodes : [{ type: 'paragraph', content: [{ type: 'text', text: ' ' }] }] };
}

// ── Parse markdown into structured fields ──
function parseMarkdown(md) {
  const lines = md.split('\n');
  const titleLine = lines.find(l => l.startsWith('# '));
  const title = titleLine ? titleLine.replace(/^# /, '') : 'Untitled';
  const titleIdx = lines.indexOf(titleLine);

  // Body: everything between title and the known ## sections
  const knownSections = ['Acceptance Criteria', 'Priority', 'Estimate', 'Component', 'Labels'];
  const bodyLines = [];
  for (let j = (titleIdx >= 0 ? titleIdx + 1 : 0); j < lines.length; j++) {
    const l = lines[j];
    if (l.startsWith('## ') && knownSections.some(s => l === '## ' + s)) break;
    bodyLines.push(l);
  }
  // Trim leading/trailing empty lines
  while (bodyLines.length && !bodyLines[0].trim()) bodyLines.shift();
  while (bodyLines.length && !bodyLines[bodyLines.length - 1].trim()) bodyLines.pop();
  const bodyMarkdown = bodyLines.join('\n');

  function getSection(heading) {
    const start = lines.findIndex(l => l === '## ' + heading);
    if (start === -1) return [];
    const out = [];
    for (let j = start + 1; j < lines.length; j++) {
      if (lines[j].startsWith('## ')) break;
      if (lines[j].trim()) out.push(lines[j]);
    }
    return out;
  }
  function getField(heading) { const s = getSection(heading); return s.length ? s[0].trim() : ''; }

  const criteria = getSection('Acceptance Criteria').filter(l => l.startsWith('- ')).map(l => l.replace(/^- /, ''));
  const priority = getField('Priority') || ($env.JIRA_DEFAULT_PRIORITY || 'Medium');
  const estimate = getField('Estimate');
  const component = getField('Component');
  const labelsStr = getField('Labels');
  const labels = ['ai-generated'];
  if (labelsStr) labels.push(...labelsStr.split(',').map(l => l.trim()).filter(Boolean));

  return { title, bodyMarkdown, criteria, priority, estimate, component, labels };
}

// ── Build Jira issue fields with ADF description ──
function buildJiraFields(parsed, issueType, parentKey, formComponent, assignee, reporter) {
  // Build the full description as markdown, then convert to ADF
  let fullMd = parsed.bodyMarkdown || '';
  if (parsed.criteria.length > 0) {
    if (fullMd) fullMd += '\n\n';
    fullMd += '## Acceptance Criteria\n';
    for (const c of parsed.criteria) fullMd += '- ' + c + '\n';
  }

  const fields = {
    summary: parsed.title,
    description: mdToAdf(fullMd),
    priority: { name: parsed.priority },
    labels: parsed.labels
  };
  const comp = parsed.component || formComponent || ($env.JIRA_DEFAULT_COMPONENT || '');
  if (comp) fields.components = [{ name: comp }];
  // Jira Cloud requires accountId (not email). If value contains @, skip it.
  if (assignee && !assignee.includes('@')) fields.assignee = { accountId: assignee };
  if (reporter && !reporter.includes('@')) fields.reporter = { accountId: reporter };
  if (parentKey) fields.parent = { key: parentKey };
  return fields;
}

function extractKey(input) {
  if (!input) return '';
  const browseMatch = input.match(/\/browse\/([A-Z]+-\d+)/);
  if (browseMatch) return browseMatch[1];
  if (input.match(/^[A-Z]+-\d+$/)) return input;
  return input.trim();
}

// ── Main ──
const body = $input.first().json.body;
const epicMarkdown = body.epicMarkdown || '';
const taskMarkdowns = body.taskMarkdowns || [];
const epicKey = extractKey(body.epicKey || '');
const taskKeys = (body.taskKeys || []).map(k => extractKey(k));
const taskAssignees = body.taskAssignees || [];
const formComponent = body.component || '';
const formAssignee = body.assignee || ($env.JIRA_DEFAULT_ASSIGNEE || '');
const formReporter = body.reporter || '';

const epicParsed = parseMarkdown(epicMarkdown);
const epicIssueType = $env.JIRA_EPIC_ISSUE_TYPE || 'Epic';

let epicApiBody, epicMethod, epicUrl;
if (epicKey) {
  epicMethod = 'PUT';
  epicUrl = $env.JIRA_BASE_URL + '/rest/api/3/issue/' + epicKey;
  epicApiBody = { fields: buildJiraFields(epicParsed, epicIssueType, null, formComponent, formAssignee, formReporter) };
} else {
  epicMethod = 'POST';
  epicUrl = $env.JIRA_BASE_URL + '/rest/api/3/issue';
  const fields = buildJiraFields(epicParsed, epicIssueType, null, formComponent, formAssignee, formReporter);
  fields.project = { key: $env.JIRA_PROJECT_KEY };
  fields.issuetype = { name: epicIssueType };
  epicApiBody = { fields };
}

return [{ json: { epicApiBody, epicMethod, epicUrl, epicKey, epicTitle: epicParsed.title, taskMarkdowns, taskKeys, taskAssignees, isUpdate: !!epicKey, formComponent, formAssignee, formReporter } }];

